Greedy insertion with best‑cost selection per order using marginal distance increase plus time window penalty weighted by load ratio.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	const maxTriesPerOrder = MAXASSIGNS * 3
	type cand struct {
		assignIdx int
		costDelta float64
		ok        bool
	}
	saveStates := make([]Assign, MAXASSIGNS)

	for orderID := 0; orderID < len(oris); orderID++ {
		ori := oris[orderID]
		des := dess[orderID]
		shipID := total_ship + orderID

		bestCand := cand{costDelta: 1e18, ok: false}
		fallbackIdx := -1

		for try := 0; try < 2; try++ {
			limit := dispatch.AssignsLen
			if try == 1 && !bestCand.ok {
				limit++
				if limit > MAXASSIGNS {
					limit = MAXASSIGNS
				}
				if fallbackIdx >= 0 && fallbackIdx < limit {
					continue
				}
			}
			for idx := 0; idx < limit; idx++ {
				saveStates[idx] = dispatch.Assigns[idx]

				addOK := dispatch.Assigns[idx].AddShip(shipID, ori, des)
				if !addOK {
					dispatch.Assigns[idx] = saveStates[idx]
					if try == 1 && fallbackIdx < 0 && idx >= dispatch.AssignsLen && idx < MAXASSIGNS {
						fallbackIdx = idx
					}
					continue
				}
				dispatch.Assigns[idx].GenRoute()
				currentCost := dispatch.Assigns[idx].Cost
				delta := currentCost - saveStates[idx].Cost

				if delta < 0 || saveStates[idx].Cost < 0 {
					delta = currentCost
				}

				loadFactor := 1.0
				if ori.Load > 0 || des.Load > 0 {
					baseLoad := 10.0
					loadSum := float64(ori.Load + des.Load)
					loadFactor = 1.0 + 0.5*(loadSum/(baseLoad+loadSum))
				}
				score := delta * loadFactor

				if score < bestCand.costDelta {
					bestCand.assignIdx = idx
					bestCand.costDelta = score
					bestCand.ok = true
				}

				dispatch.Assigns[idx].RemoveShip(shipID)
				dispatch.Assigns[idx].GenRoute()
				if dispatch.Assigns[idx].Cost != saveStates[idx].Cost {
					dispatch.Assigns[idx] = saveStates[idx]
				} else {
					dispatch.Assigns[idx] = saveStates[idx]
				}
			}
		}

		targetIdx := -1
		if bestCand.ok {
			targetIdx = bestCand.assignIdx
		} else {
			if fallbackIdx < 0 {
				for i := 0; i < MAXASSIGNS; i++ {
					if i >= dispatch.AssignsLen {
						targetIdx = i
						break
					}
				}
			} else {
				targetIdx = fallbackIdx
			}
		}

		if targetIdx >= 0 {
			saveBeforeCommit := dispatch.Assigns[targetIdx]
			okCommit := dispatch.Assigns[targetIdx].AddShip(shipID, ori, des)
			if !okCommit {
				dispatch.Assigns[targetIdx] = saveBeforeCommit
				if targetIdx >= dispatch.AssignsLen && targetIdx < MAXASSIGNS {
					newAssign := Assign{}
					dispatch.Assigns[targetIdx] = newAssign
					okFallback := dispatch.Assigns[targetIdx].AddShip(shipID, ori, des)
					if okFallback {
						dispatch.Assigns[targetIdx].GenRoute()
						if targetIdx >= dispatch.AssignsLen {
							dispatch.AssignsLen = targetIdx + 1
						}
					}
				}
			} else {
				dispatch.Assigns[targetIdx].GenRoute()
				if targetIdx >= dispatch.AssignsLen {
					dispatch.AssignsLen = targetIdx + 1
				}
			}
		}
	}

	dispatch.RenewnTotalCost()
	return dispatch

